public boolean compare(String word1, String word2) {
    int[] counts_w1 = new int[26];
    int[] counts_w2 = new int[26];
    for (char c : word1.toCharArray()) counts_w1[c - 'a']++;
    for (char c : word2.toCharArray()) counts_w2[c - 'a']++;

    for (int i = 0; i < 26; i++) {
        if (counts_w1[i] > 0 && counts_w2[i] > 0) return true;
    }
    return false;
}

public boolean swapEqualDistinct(String word1, String word2) {
    boolean exch = compare(word1, word2);
    return exch && word1.length() == word2.length();
}
```

